  useEffect(() => {
    if (allowLooseSale) return
    cartItems.forEach((item) => {
      const tps = item.tabletsPerStrip ?? 1
      if (tps > 1 && item.quantity % tps !== 0) {
        store.updateQty(item.medicineId, Math.ceil(item.quantity / tps) * tps)
      }
    })
  }, [allowLooseSale, cartItems, store])

